package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testWithCommentMarker() throws Exception {
        // Given
        char commentMarker = '#';
        CSVFormat expected = CSVFormat.DEFAULT.withCommentMarker(commentMarker);

        // When
        CSVFormat result = invokeWithCommentMarker(csvFormat, commentMarker);

        // Then
        assertEquals(expected, result);
    }

    private CSVFormat invokeWithCommentMarker(CSVFormat csvFormat, char commentMarker) throws Exception {
        CSVFormat instance = mock(CSVFormat.class);
        when(instance.withCommentMarker(Character.valueOf(commentMarker))).thenCallRealMethod();
        return instance.withCommentMarker(commentMarker);
    }
}
